**WIRE THE TOOLBAR** (handles selection wrap, collapsed cursor, line-prefix actions):
```javascript
const editor = document.getElementById('editor-input');
const counts = document.getElementById('editor-counts');

// Wrap or unwrap the current selection with markers
function wrapSelection(before, after = before, placeholder = 'text') {
  const start = editor.selectionStart, end = editor.selectionEnd;
  const selected = editor.value.slice(start, end) || placeholder;
  const newText = before + selected + after;
  editor.setRangeText(newText, start, end, 'select');
  // Position cursor: if no original selection, leave selected; else select wrapped
  if (start === end) {
    editor.setSelectionRange(start + before.length, start + before.length + placeholder.length);
  } else {
    editor.setSelectionRange(start + before.length, start + before.length + selected.length);
  }
  editor.focus();
  updateCounts();
}

// Add a prefix to each selected line (for lists, headings, blockquote)
function prefixLines(prefix) {
  const start = editor.selectionStart, end = editor.selectionEnd;
  const value = editor.value;
  // Expand selection to full lines
  const lineStart = value.lastIndexOf('\n', start - 1) + 1;
  const lineEnd = value.indexOf('\n', end);
  const trueEnd = lineEnd === -1 ? value.length : lineEnd;
  const block = value.slice(lineStart, trueEnd);
  const newBlock = block.split('\n').map(line => prefix + line).join('\n');
  editor.setRangeText(newBlock, lineStart, trueEnd, 'select');
  editor.focus();
  updateCounts();
}

// Toolbar action dispatcher
document.querySelectorAll('.tb-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    const action = btn.dataset.md;
    switch (action) {
      case 'bold':      wrapSelection('**'); break;
      case 'italic':    wrapSelection('*'); break;
      case 'code':      wrapSelection('`'); break;
      case 'codeblock': wrapSelection('\n```\n', '\n```\n', 'code'); break;
      case 'link':      {
        const url = prompt('URL:', 'https://');
        if (url) wrapSelection('[', `](${url})`, 'link text');
        break;
      }
      case 'heading':   prefixLines('## '); break;
      case 'list':      prefixLines('- '); break;
      case 'todo':      prefixLines('- [ ] '); break;
    }
  });
});

// Keyboard shortcuts
editor.addEventListener('keydown', (e) => {
  const meta = e.metaKey || e.ctrlKey;
  if (!meta) return;
  if (e.key === 'b') { e.preventDefault(); wrapSelection('**'); }
  if (e.key === 'i') { e.preventDefault(); wrapSelection('*'); }
  if (e.key === 'k') { e.preventDefault();
    const url = prompt('URL:', 'https://');
    if (url) wrapSelection('[', `](${url})`, 'link text');
  }
});

// Word/char counter
function updateCounts() {
  const text = editor.value;
  const words = text.trim() ? text.trim().split(/\s+/).length : 0;
  counts.textContent = `${words} word${words === 1 ? '' : 's'} · ${text.length} char${text.length === 1 ? '' : 's'}`;
}
editor.addEventListener('input', updateCounts);
updateCounts();
```

